class Stack:
    def __init__(self):
        self.items = []

    def push(self, x):
        self.items.append(x)

    def pop_two(self):
        # BUG: no check if len >= 2
        return self.items.pop(), self.items.pop()

    def __len__(self):
        return len(self.items)


def run_ops(ops):
    s = Stack()
    for op in ops:
        if op[0] == 'push':
            s.push(op[1])
        elif op[0] == 'pop2':
            print(s.pop_two())


def main():
    ops = [('push', 1), ('pop2',), ('pop2',)]
    run_ops(ops)


if __name__ == '__main__':
    main()
